use crate::constants::{
    BASELINE_VOTES_FOR_STABILITY, BPS_DENOMINATOR, FRAGILITY_HIGH, FRAGILITY_MEDIUM,
    LATE_RATIO_HIGH_BPS, LATE_RATIO_MEDIUM_BPS, LATE_WINDOW_SECS, MAX_FRAGILITY_SCORE,
    VELOCITY_HIGH, VELOCITY_MEDIUM,
};
use crate::state::ParticipationMetrics;

#[repr(u8)]
#[derive(Copy, Clone, Debug, Eq, PartialEq)]
pub enum RiskLevel {
    Low = 0,
    Medium = 1,
    High = 2,
}

#[repr(u16)]
#[derive(Copy, Clone, Debug, Eq, PartialEq)]
pub enum RiskReasonCode {
    NotComputed = 0,
    LateVoteConcentration = 100,
    QuorumFragility = 200,
    ParticipationVelocitySpike = 300,
    MixedSignals = 400,
}

pub fn classify_risk(
    metrics: &ParticipationMetrics,
    now_ts: i64,
    voting_end_ts: i64,
) -> (RiskLevel, RiskReasonCode) {
    let in_late_window = voting_end_ts <= now_ts || (voting_end_ts - now_ts) <= LATE_WINDOW_SECS;

    let high_late = metrics.late_vote_ratio_bps >= LATE_RATIO_HIGH_BPS;
    let high_fragility = metrics.quorum_fragility_score >= FRAGILITY_HIGH;
    let high_velocity = metrics.participation_velocity >= VELOCITY_HIGH && in_late_window;

    if high_late || high_fragility || high_velocity {
        let reason = if high_late {
            RiskReasonCode::LateVoteConcentration
        } else if high_fragility {
            RiskReasonCode::QuorumFragility
        } else {
            RiskReasonCode::ParticipationVelocitySpike
        };
        return (RiskLevel::High, reason);
    }

    let medium_late = metrics.late_vote_ratio_bps >= LATE_RATIO_MEDIUM_BPS;
    let medium_fragility = metrics.quorum_fragility_score >= FRAGILITY_MEDIUM;
    let medium_velocity = metrics.participation_velocity >= VELOCITY_MEDIUM;

    if medium_late || medium_fragility || medium_velocity {
        return (RiskLevel::Medium, RiskReasonCode::MixedSignals);
    }

    (RiskLevel::Low, RiskReasonCode::NotComputed)
}

pub fn compute_fragility(
    total_votes: u64,
    late_vote_ratio_bps: u16,
    now_ts: i64,
    voting_end_ts: i64,
) -> u16 {
    let participation_component = if total_votes >= BASELINE_VOTES_FOR_STABILITY {
        0
    } else {
        (((BASELINE_VOTES_FOR_STABILITY - total_votes) * BPS_DENOMINATOR)
            / BASELINE_VOTES_FOR_STABILITY) as u16
    };

    let time_pressure_component = if now_ts >= voting_end_ts {
        1_500
    } else {
        let remaining = (voting_end_ts - now_ts) as u64;
        let pressure = (1_000u64).saturating_sub(remaining.min(1_000));
        pressure as u16
    };

    let late_component = late_vote_ratio_bps / 2;
    participation_component
        .saturating_add(late_component)
        .saturating_add(time_pressure_component)
        .min(MAX_FRAGILITY_SCORE)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::state::ParticipationMetrics;

    fn metrics(
        total_votes: u64,
        late_votes: u64,
        velocity: u64,
        late_ratio_bps: u16,
        fragility: u16,
    ) -> ParticipationMetrics {
        ParticipationMetrics {
            total_votes,
            early_votes: total_votes.saturating_sub(late_votes),
            late_votes,
            last_update_ts: 0,
            participation_velocity: velocity,
            late_vote_ratio_bps: late_ratio_bps,
            quorum_fragility_score: fragility,
            bump: 0,
        }
    }

    #[test]
    fn classifies_high_risk_on_late_vote_concentration() {
        let m = metrics(100, 70, 2, 7_000, 2_000);
        let (level, reason) = classify_risk(&m, 1_000, 1_100);
        assert_eq!(level, RiskLevel::High);
        assert_eq!(reason, RiskReasonCode::LateVoteConcentration);
    }

    #[test]
    fn classifies_medium_risk_on_mixed_signals() {
        let m = metrics(120, 20, 7, 2_500, 3_000);
        let (level, reason) = classify_risk(&m, 1_000, 1_900);
        assert_eq!(level, RiskLevel::Medium);
        assert_eq!(reason, RiskReasonCode::MixedSignals);
    }

    #[test]
    fn computes_fragility_bounded_to_bps_range() {
        let score = compute_fragility(0, 10_000, 500, 600);
        assert!(score <= MAX_FRAGILITY_SCORE);
    }
}

use anchor_lang::{AccountDeserialize, InstructionData, ToAccountMetas};
use solana_program::{account_info::AccountInfo, entrypoint::ProgramResult};
use solana_program_test::{processor, ProgramTest, ProgramTestContext};
use solana_sdk::{
    instruction::Instruction, pubkey::Pubkey, signature::Signer, system_program,
    transaction::Transaction,
};

use cfo_oracle::{
    constants::MAX_FRAGILITY_SCORE,
    risk::{RiskLevel, RiskReasonCode},
    state::{ParticipationMetrics, ProposalAnalysis, RiskSignal},
};

const VOTING_START_TS: i64 = 1_700_000_000;
const VOTING_END_TS: i64 = 4_000_000_000;
const EXPECTED_EXEC_TS: i64 = 4_000_000_600;

#[derive(Debug, Clone, Copy)]
struct ProposalPdas {
    proposal_analysis: Pubkey,
    participation_metrics: Pubkey,
    risk_signal: Pubkey,
}

fn derive_pdas(dao_governance_program: Pubkey, dao_proposal_account: Pubkey) -> ProposalPdas {
    let (proposal_analysis, _) = Pubkey::find_program_address(
        &[
            b"proposal_analysis",
            dao_governance_program.as_ref(),
            dao_proposal_account.as_ref(),
        ],
        &cfo_oracle::id(),
    );
    let (participation_metrics, _) = Pubkey::find_program_address(
        &[b"participation_metrics", proposal_analysis.as_ref()],
        &cfo_oracle::id(),
    );
    let (risk_signal, _) = Pubkey::find_program_address(
        &[b"risk_signal", proposal_analysis.as_ref()],
        &cfo_oracle::id(),
    );
    ProposalPdas {
        proposal_analysis,
        participation_metrics,
        risk_signal,
    }
}

async fn setup() -> ProgramTestContext {
    ProgramTest::new(
        "cfo_oracle",
        cfo_oracle::id(),
        processor!(process_instruction),
    )
    .start_with_context()
    .await
}

unsafe fn coerce_account_infos_lifetime<'a>(accounts: &[AccountInfo<'_>]) -> &'a [AccountInfo<'a>] {
    // SAFETY: ProgramTest provides account infos that remain valid for the duration
    // of each instruction invocation; this cast is only used to bridge Anchor's
    // stricter lifetime signature in tests.
    unsafe { std::mem::transmute(accounts) }
}

fn process_instruction(
    program_id: &Pubkey,
    accounts: &[AccountInfo<'_>],
    instruction_data: &[u8],
) -> ProgramResult {
    // SAFETY: See helper docs above.
    let anchor_accounts: &[AccountInfo<'_>] = unsafe { coerce_account_infos_lifetime(accounts) };
    cfo_oracle::entry(program_id, anchor_accounts, instruction_data)
}

async fn process_ix(ctx: &mut ProgramTestContext, ix: Instruction) -> Result<(), String> {
    ctx.last_blockhash = ctx
        .banks_client
        .get_latest_blockhash()
        .await
        .map_err(|e| e.to_string())?;

    let tx = Transaction::new_signed_with_payer(
        &[ix],
        Some(&ctx.payer.pubkey()),
        &[&ctx.payer],
        ctx.last_blockhash,
    );
    ctx.banks_client
        .process_transaction(tx)
        .await
        .map_err(|e| e.to_string())
}

async fn fetch_account<T: AccountDeserialize>(
    ctx: &mut ProgramTestContext,
    key: Pubkey,
) -> Result<T, String> {
    let account = ctx
        .banks_client
        .get_account(key)
        .await
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "account not found".to_string())?;
    let mut data = account.data.as_slice();
    T::try_deserialize(&mut data).map_err(|e| e.to_string())
}

async fn register(
    ctx: &mut ProgramTestContext,
    dao_governance_program: Pubkey,
    dao_proposal_account: Pubkey,
) -> Result<ProposalPdas, String> {
    let pdas = derive_pdas(dao_governance_program, dao_proposal_account);

    let ix = Instruction {
        program_id: cfo_oracle::id(),
        accounts: cfo_oracle::accounts::RegisterProposal {
            proposal_creator: ctx.payer.pubkey(),
            proposal_analysis: pdas.proposal_analysis,
            participation_metrics: pdas.participation_metrics,
            risk_signal: pdas.risk_signal,
            system_program: system_program::id(),
        }
        .to_account_metas(None),
        data: cfo_oracle::instruction::RegisterProposal {
            dao_governance_program,
            dao_proposal_account,
            voting_start_ts: VOTING_START_TS,
            voting_end_ts: VOTING_END_TS,
            expected_execution_ts: EXPECTED_EXEC_TS,
        }
        .data(),
    };

    process_ix(ctx, ix).await?;
    Ok(pdas)
}

#[tokio::test]
async fn register_proposal_initializes_pdas_and_defaults() {
    let mut ctx = setup().await;
    let dao_governance_program = Pubkey::new_unique();
    let dao_proposal_account = Pubkey::new_unique();

    let pdas = register(&mut ctx, dao_governance_program, dao_proposal_account)
        .await
        .expect("register should succeed");

    let proposal: ProposalAnalysis = fetch_account(&mut ctx, pdas.proposal_analysis)
        .await
        .expect("proposal account should deserialize");
    assert_eq!(proposal.dao_governance_program, dao_governance_program);
    assert_eq!(proposal.dao_proposal_account, dao_proposal_account);
    assert_eq!(proposal.proposal_creator, ctx.payer.pubkey());
    assert_eq!(proposal.voting_start_ts, VOTING_START_TS);
    assert_eq!(proposal.voting_end_ts, VOTING_END_TS);
    assert_eq!(proposal.expected_execution_ts, EXPECTED_EXEC_TS);

    let metrics: ParticipationMetrics = fetch_account(&mut ctx, pdas.participation_metrics)
        .await
        .expect("metrics account should deserialize");
    assert_eq!(metrics.total_votes, 0);
    assert_eq!(metrics.early_votes, 0);
    assert_eq!(metrics.late_votes, 0);
    assert_eq!(metrics.participation_velocity, 0);
    assert_eq!(metrics.late_vote_ratio_bps, 0);
    assert_eq!(metrics.quorum_fragility_score, MAX_FRAGILITY_SCORE);

    let signal: RiskSignal = fetch_account(&mut ctx, pdas.risk_signal)
        .await
        .expect("signal account should deserialize");
    assert_eq!(signal.risk_level, RiskLevel::Low as u8);
    assert_eq!(signal.risk_reason_code, RiskReasonCode::NotComputed as u16);
    assert_eq!(signal.computed_at, 0);
}

